import{_ as i,o as a,c as t,ag as o}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Beveiliging","description":"","frontmatter":{},"headers":[],"relativePath":"nl/account/security.md","filePath":"nl/account/security.md"}'),n={name:"nl/account/security.md"};function r(l,e,s,c,g,h){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="beveiliging" tabindex="-1">Beveiliging <a class="header-anchor" href="#beveiliging" aria-label="Permalink to &quot;Beveiliging&quot;">​</a></h1><p>Bescherm je account met sterke authenticatie en monitor toegang.</p><h2 id="wachtwoord" tabindex="-1">Wachtwoord <a class="header-anchor" href="#wachtwoord" aria-label="Permalink to &quot;Wachtwoord&quot;">​</a></h2><p>Gebruik een sterk, uniek wachtwoord voor je MyCompanyDesk-account. Wijzig het via <strong>Profiel &gt; Wachtwoord</strong>.</p><h3 id="wachtwoordvereisten" tabindex="-1">Wachtwoordvereisten <a class="header-anchor" href="#wachtwoordvereisten" aria-label="Permalink to &quot;Wachtwoordvereisten&quot;">​</a></h3><ul><li>Minimaal 8 tekens</li><li>Mix van letters, cijfers en symbolen aanbevolen</li></ul><h2 id="tweefactorauthenticatie" tabindex="-1">Tweefactorauthenticatie <a class="header-anchor" href="#tweefactorauthenticatie" aria-label="Permalink to &quot;Tweefactorauthenticatie&quot;">​</a></h2><p>Voeg een extra beveiligingslaag toe aan je account:</p><ol><li>Ga naar <strong>Profiel &gt; Beveiliging</strong></li><li>Klik op <strong>Tweefactorauthenticatie inschakelen</strong></li><li>Scan de QR-code met je authenticator-app (Google Authenticator, Authy, etc.)</li><li>Vul de verificatiecode in ter bevestiging</li><li>Sla je <strong>herstelcodes</strong> op op een veilige locatie</li></ol><p>Met 2FA ingeschakeld heb je zowel je wachtwoord als een code van je authenticator-app nodig om in te loggen.</p><h3 id="_2fa-uitschakelen" tabindex="-1">2FA uitschakelen <a class="header-anchor" href="#_2fa-uitschakelen" aria-label="Permalink to &quot;2FA uitschakelen&quot;">​</a></h3><ol><li>Ga naar <strong>Profiel &gt; Beveiliging</strong></li><li>Klik op <strong>Tweefactorauthenticatie uitschakelen</strong></li><li>Vul je wachtwoord in ter bevestiging</li></ol><h2 id="sessiebeheer" tabindex="-1">Sessiebeheer <a class="header-anchor" href="#sessiebeheer" aria-label="Permalink to &quot;Sessiebeheer&quot;">​</a></h2><p>Bekijk en beheer je actieve sessies:</p><ul><li>Bekijk alle apparaten en browsers waar je bent ingelogd</li><li>Bekijk de laatste activiteitstijd per sessie</li><li><strong>Intrekken</strong> van sessies die je niet herkent</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Als je een sessie ziet die je niet herkent, trek deze dan direct in en wijzig je wachtwoord.</p></div><h2 id="social-login" tabindex="-1">Social login <a class="header-anchor" href="#social-login" aria-label="Permalink to &quot;Social login&quot;">​</a></h2><p>Als je Google of Microsoft gebruikt om in te loggen:</p><ul><li>Je authenticatie wordt afgehandeld door de aanbieder</li><li>MyCompanyDesk ziet of bewaart je Google/Microsoft-wachtwoord nooit</li><li>Je kunt social login loskoppelen via <strong>Profiel &gt; Gekoppelde apps</strong></li></ul><h2 id="gegevensbescherming" tabindex="-1">Gegevensbescherming <a class="header-anchor" href="#gegevensbescherming" aria-label="Permalink to &quot;Gegevensbescherming&quot;">​</a></h2><p>MyCompanyDesk neemt gegevensbeveiliging serieus:</p><ul><li>Alle gegevens worden verstuurd via HTTPS</li><li>Wachtwoorden worden gehasht met bcrypt</li><li>Databaseverbindingen zijn versleuteld</li><li>Regelmatige back-ups zorgen voor gegevensveiligheid</li><li>AVG-conforme gegevensverwerking</li></ul><h2 id="account-verwijderen" tabindex="-1">Account verwijderen <a class="header-anchor" href="#account-verwijderen" aria-label="Permalink to &quot;Account verwijderen&quot;">​</a></h2><p>Als je je account moet verwijderen:</p><ol><li>Ga naar <strong>Profiel &gt; Gegevens</strong></li><li>Klik op <strong>Account verwijderen</strong></li><li>Vul je wachtwoord in ter bevestiging</li><li>Al je gegevens worden permanent verwijderd</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Accountverwijdering is onomkeerbaar. Exporteer je gegevens eerst als je een back-up nodig hebt.</p></div>',26)])])}const p=i(n,[["render",r]]);export{u as __pageData,p as default};
